SourceCode.Declaration:
/// <summary>
/// Data contract for the creation of unsold journals in the ETGSPAIN model.
/// This class is used to pass the necessary parameters for the unsold journal creation process.
/// </summary>
[
    DataContract
]
class ETGSPAINUnsoldJournalCreateContract implements SysOperationValidatable
{
    ETGSPAINUnsoldQty       etgspainUnsoldQty;
    RefRecId                refRecId;
    ETGSPAINUnsoldJournalId etgspainUnsoldJournalId;

}

Method.Source:
/// <summary>
/// Gets or sets the quantity of unsold items for the journal.
/// </summary>
/// <param name="_etgspainUnsoldQty">The unsold quantity to be set.</param>
/// <returns>The unsold quantity.</returns>
[
    DataMember
]
public ETGSPAINUnsoldQty parmETGSPAINUnsoldQty(ETGSPAINUnsoldQty _etgspainUnsoldQty = etgspainUnsoldQty)
{
    etgspainUnsoldQty = _etgspainUnsoldQty;
    return etgspainUnsoldQty;
}

/// <summary>
/// Gets or sets the reference record ID for the unsold journal.
/// </summary>
/// <param name="_refRecId">The reference record ID.</param>
/// <returns>The reference record ID.</returns>
public RefRecId parmRefRecId(RefRecId _refRecId = refRecId)
{
    refRecId = _refRecId;
    return refRecId;
}

    /// <summary>
    /// Gets or sets the unsold journal ID.
    /// </summary>
    /// <param name="_etgspainUnsoldJournalId">The unsold journal ID.</param>
    /// <returns>The unsold journal ID.</returns>
    public ETGSPAINUnsoldJournalId parmETGSPAINUnsoldJournalId(ETGSPAINUnsoldJournalId _etgspainUnsoldJournalId = etgspainUnsoldJournalId)
	{
		etgspainUnsoldJournalId = _etgspainUnsoldJournalId;
		return etgspainUnsoldJournalId;
	}

/// <summary>
/// Validates the input parameters for the unsold journal creation process.
/// </summary>
/// <returns>True if the input parameters are valid, otherwise False.</returns>
public boolean validate()
{
    boolean isValid = true;

    ETGSPAINUnsoldInventTrans etgspainUnsoldInventTrans = ETGSPAINUnsoldInventTrans::findRefRecId(refRecId, true);

    if (etgspainUnsoldQty > etgspainUnsoldInventTrans.MaxUnsoldQty)
    {
        isValid = checkFailed(strFmt("@ETGSPAINLabels:ETGSPAINUnsoldQtyValidateWarning", etgspainUnsoldInventTrans.MaxUnsoldQty));
    }

    return isValid;
}
